// =============================================
// FILTRAR E FORMATAR DADOS DA PLANILHA
// Normaliza números de telefone e prepara dados para o Supabase
// =============================================

// Obter todas as linhas lidas do Google Sheets
const rows = $input.all();
const formattedLeads = [];

for (const row of rows) {
  const data = row.json;

  // 1. Validar e limpar número de telefone
  let rawPhone = data.Telefone || data.telefone || '';
  if (!rawPhone) continue;

  // Remover caracteres não numéricos
  let phone = rawPhone.toString().replace(/\D/g, '');

  // Tratar telefones brasileiros (adicionar DDI 55 se não tiver)
  if (phone.length === 10 || phone.length === 11) {
    phone = '55' + phone;
  }

  // Ignorar números inválidos
  if (phone.length < 10) continue;

  // 2. Extrair e normalizar segmento
  let segmento = (data.Segmento || data.segmento || 'servicos').toLowerCase().trim();
  // Mapear segmentos válidos
  const segmentosValidos = ['clinica', 'imobiliaria', 'loja', 'servicos'];
  if (!segmentosValidos.includes(segmento)) {
    segmento = 'servicos';
  }

  formattedLeads.push({
    json: {
      telefone: phone,
      nome_contato: data.Nome || data.nome || null,
      nome_empresa: data.Empresa || data.empresa || null,
      segmento: segmento,
      cidade: data.Cidade || data.cidade || null,
      origem: data.Origem || data.origem || 'google_sheets',
      observacao: data.Observacao || data.observacao || null,
      status: 'PENDENTE' // Status inicial para outbound
    }
  });
}

return formattedLeads;
